import java.util.*;
public class MutableKey {
    static class Box {
        int val;
        Box(int v) { val = v; }
        public int hashCode() { return val; }
        public boolean equals(Object o) { return o instanceof Box && ((Box)o).val == val; }
    }
    public static void main(String[] args) {
        Set<Box> set = new HashSet<>();
        Box b = new Box(5);
        set.add(b);
        b.val = 10;   // bug: mutating the key after insertion
        System.out.println(set.contains(b));
    }
}
